// --- ВСПОМОГАТЕЛЬНАЯ ЛОГИКА ОПРЕДЕЛЕНИЯ ПЕРИОДА ДЛЯ ЗАДАНИЯ 5 ---
function getYearFromFact(fact) { 
    let m = fact.year.match(/\d+/); 
    return m ? parseInt(m[0], 10) : 9999; 
}

task5Data.forEach(d => {
    let y = parseInt(d.year, 10);
    if (y <= 1700) d.c = 'early'; 
    else if (y <= 1800) d.c = '18th'; 
    else if (y <= 1900) d.c = '19th'; 
    else d.c = '20th';
});

